import React, { useCallback } from 'react';
import { hasPermissionCode, usePeriodJobPermissions } from '../../../hooks/usePeriodJobPermissions';
import { PeriodActionPanel } from '../../../components/kt/PeriodActionPanel';
import { ktService } from '../../../services/kt/ktService';
import { PERIOD_JOB_TYPES } from '../../../constants/periodJobTypes';
import { PERIOD_REFERENCE_NO } from '../../../constants/periodProcessReferences';
import { periodProcessStatusLabel } from '../../../utils/periodProcessStatusLabel';

const TinhGiaVonPage: React.FC = () => {
  const { canRun, canPost } = usePeriodJobPermissions('cost-calculation');
  void hasPermissionCode;
  const getStatus = useCallback(
    async (m: number, y: number) => periodProcessStatusLabel(await ktService.getCostCalculationStatus(m, y)),
    [],
  );

  return (
    <PeriodActionPanel
      testIdPrefix="kt-tinh-gia-von"
      title="Tính giá vốn"
      icon="fa-calculator"
      runLabel="Tính giá vốn"
      postLabel="Ghi sổ"
      jobType={PERIOD_JOB_TYPES.CostCalculation}
      referenceNo={PERIOD_REFERENCE_NO.CostCalculation}
      getStatus={getStatus}
      onRun={(m, y) => ktService.runCostCalculation(m, y)}
      onPost={(m, y) => ktService.postCostCalculation(m, y)}
      runPermitted={canRun}
      postPermitted={canPost}
    />
  );
};

export default TinhGiaVonPage;
